  const compose=(position,yaw,lean,scale)=>{rotation.setFromAxisAngle(upAxis,yaw);if(lean){leanRotation.setFromAxisAngle(forwardAxis,lean);rotation.multiply(leanRotation)}return new ue().compose(position,rotation,scale)};
