    proxy.position.set(x,height,z);proxy.rotation.y=random.range(0,Math.PI*2);proxy.userData.treeId=`tree-${count}`;proxy.userData.treeIndex=count;proxy.userData.treeInstanceMatrices=matrices;proxy.userData.health=health;proxy.userData.maxHealth=health;proxy.userData.timber=Math.round(3+size*9*heightScale);proxy.userData.treeSize=health===1?"small":health===2?"medium":"large";proxy.userData.heightScale=heightScale;proxy.userData.widthScale=widthScale;proxy.userData.depthScale=depthScale;proxy.userData.lean=lean;proxy.userData.treeVariant=count%8;proxy.userData.treeSilhouette=spherical?"spherical":"triangular";proxy.userData.swaySeed=random.range(0,100);proxy.userData.harvestableTree=!0;
